import React from 'react';
import { Notification as CarbonNotification } from '@carbon/react';

const Notification = (props) => {
    const {
        id,
        setProps,
        children,
        className,
        ...otherProps
    } = props;

    return (
        <CarbonNotification
            id={id}
            className={className}
            {...otherProps}
        >
            {children}
        </CarbonNotification>
    );
};

Notification.defaultProps = {
    className: ''
};

export default Notification;
